import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.D5wUhsuj.js";const h=JSON.parse('{"title":"Installation Planning","description":"","frontmatter":{},"headers":[],"relativePath":"admin/installation.md","filePath":"admin/installation.md","lastUpdated":1783546178000}'),i={name:"admin/installation.md"};function s(n,e,l,d,c,p){return a(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="installation-planning" tabindex="-1">Installation Planning <a class="header-anchor" href="#installation-planning" aria-label="Permalink to &quot;Installation Planning&quot;">​</a></h1><p>This page lists the infrastructure prerequisites for installing prokube. Use it before running the release-specific installation automation.</p><h2 id="kubernetes-cluster" tabindex="-1">Kubernetes Cluster <a class="header-anchor" href="#kubernetes-cluster" aria-label="Permalink to &quot;Kubernetes Cluster&quot;">​</a></h2><p>prokube runs on Kubernetes. Supported distributions include managed Kubernetes services such as GKE, EKS, and AKS, plus self-managed clusters such as MicroK8s, kubeadm-based clusters, OpenShift, or Rancher-backed installations.</p><p>Recommended baseline for a multi-user deployment:</p><table tabindex="0"><thead><tr><th>Resource</th><th style="text-align:right;">Minimum</th><th style="text-align:right;">Recommended</th></tr></thead><tbody><tr><td>Kubernetes version</td><td style="text-align:right;"><code>1.32</code> to <code>1.35</code></td><td style="text-align:right;"><code>1.35</code></td></tr><tr><td>Nodes</td><td style="text-align:right;">3</td><td style="text-align:right;">3 or more, across failure domains where possible</td></tr><tr><td>Memory per node</td><td style="text-align:right;">32 GB</td><td style="text-align:right;">96 GB</td></tr><tr><td>CPU per node</td><td style="text-align:right;">8 cores</td><td style="text-align:right;">24 cores</td></tr><tr><td>Storage per node</td><td style="text-align:right;">100 GB</td><td style="text-align:right;">1 TB</td></tr></tbody></table><p>These values are starting points. Actual sizing depends on enabled product tracks, number of users, notebook and pipeline concurrency, model size, GPU use, retention periods, and whether platform databases and object storage run in the same cluster.</p><p>Before installation, confirm:</p><ul><li>Kubernetes version and distribution are supported by the target prokube release;</li><li>nodes have enough CPU, memory, storage, and optional GPU capacity for the selected product tracks;</li><li>the cluster has a default StorageClass and any additional classes needed for object storage, notebooks, databases, and model-serving workloads;</li><li>a CSI driver and snapshot support exist if backup workflows depend on volume snapshots;</li><li>administrators have <code>kubectl</code> and cluster-admin access for bootstrap and recovery.</li></ul><p>MicroK8s can be suitable for very small self-managed deployments. Production and multi-user deployments need capacity, availability, backup, storage, and operational controls sized for the expected workloads.</p><p>If the deployment will run GPU workloads, choose GPU hardware supported by the NVIDIA GPU Operator and confirm the selected Kubernetes distribution is supported by the operator. See <a href="./gpu.html">GPU Administration</a>.</p><h2 id="dns-and-tls" tabindex="-1">DNS and TLS <a class="header-anchor" href="#dns-and-tls" aria-label="Permalink to &quot;DNS and TLS&quot;">​</a></h2><p>Plan stable DNS and trusted TLS before onboarding users.</p><p>Most installations need DNS names that resolve to the external load balancer or ingress nodes. A common layout uses one name for the main prokube UI and APIs and a separate name for MinIO, for example:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>prokube.example.com</span></span>
<span class="line"><span>minio.prokube.example.com</span></span></code></pre></div><p>The exact hostnames depend on the deployment&#39;s ingress and object-storage configuration. Keep them stable after installation because login redirects, OIDC clients, API URLs, and generated links depend on them.</p><p>At minimum, decide:</p><ul><li>the public prokube domain;</li><li>whether MinIO uses a separate hostname;</li><li>whether applications use path-prefix routing on the main domain or dedicated subdomains;</li><li>certificate issuer and renewal process;</li><li>how private or self-signed certificate authorities are distributed to users, workloads, and platform components.</li></ul><p>TLS certificates must cover all public hostnames. Public Let&#39;s Encrypt certificates are suitable when the names are publicly reachable and ACME challenges can complete. Private certificates are possible, but clients, workloads, and platform components must trust the issuing CA.</p><p>Some prokube deployments distribute private CA trust into workloads with cert-manager trust bundles and Kyverno mutation policies. In that setup, the custom CA is published as a namespace-local bundle and injected into annotated pods, including selected Labs and pipeline workflows. Verify that the custom-CA bundle and Kyverno policies are installed before relying on private certificates for user workloads.</p><p>Several platform services rely on browser redirects. Incorrect root URLs, missing TLS trust, or changed hostnames commonly break login and OIDC flows.</p><h2 id="networking-and-firewall" tabindex="-1">Networking and Firewall <a class="header-anchor" href="#networking-and-firewall" aria-label="Permalink to &quot;Networking and Firewall&quot;">​</a></h2><p>The cluster needs outbound access for image pulls, package downloads, identity-provider endpoints, object-storage targets, and webhook integrations used by the deployment. Inbound access should be restricted to the gateways and admin access paths that are intentionally exposed.</p><p>For user traffic, allow access to:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Port</th><th>Purpose</th></tr></thead><tbody><tr><td style="text-align:right;"><code>443</code></td><td>HTTPS access to prokube, APIs, and exposed applications.</td></tr><tr><td style="text-align:right;"><code>80</code></td><td>Optional HTTP redirect to HTTPS.</td></tr></tbody></table><p>For administrator access, expose the Kubernetes API only through the deployment&#39;s approved access path, such as private networking, VPN, bastion, provider IAM, or a restricted load balancer. Do not expose cluster admin ports broadly to user networks.</p><p>Self-managed clusters also need node-to-node traffic for Kubernetes control plane, kubelet, etcd or dqlite, CNI networking, and distribution-specific agents. Examples include API server, kubelet, controller-manager, scheduler, etcd peer/client, MicroK8s dqlite, and Calico VXLAN traffic. The exact ports depend on the Kubernetes distribution and CNI.</p><p>For self-managed clusters, use the distribution&#39;s firewall guide as the source of truth. The following ports are commonly relevant for MicroK8s-style or kubeadm-style installations and should be restricted to cluster nodes or administrator networks, not broadly exposed to users:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Port</th><th>Scope</th><th>Purpose</th></tr></thead><tbody><tr><td style="text-align:right;"><code>16443</code></td><td>admin / control plane</td><td>Kubernetes API server in MicroK8s deployments. Other distributions often use <code>6443</code>.</td></tr><tr><td style="text-align:right;"><code>10250</code></td><td>node-to-control-plane</td><td>Kubelet API with authenticated TLS access.</td></tr><tr><td style="text-align:right;"><code>10257</code></td><td>control plane</td><td>kube-controller-manager HTTPS endpoint.</td></tr><tr><td style="text-align:right;"><code>10259</code></td><td>control plane</td><td>kube-scheduler HTTPS endpoint.</td></tr><tr><td style="text-align:right;"><code>2379</code></td><td>control plane</td><td>etcd client requests.</td></tr><tr><td style="text-align:right;"><code>2380</code></td><td>control plane</td><td>etcd peer communication.</td></tr><tr><td style="text-align:right;"><code>12379</code></td><td>control plane</td><td>MicroK8s etcd endpoint in deployments that use etcd.</td></tr><tr><td style="text-align:right;"><code>19001</code></td><td>control plane</td><td>MicroK8s dqlite cluster coordination.</td></tr><tr><td style="text-align:right;"><code>25000</code></td><td>cluster nodes</td><td>MicroK8s cluster-agent traffic.</td></tr><tr><td style="text-align:right;"><code>4789</code></td><td>cluster nodes</td><td>Calico VXLAN overlay traffic when Calico VXLAN is used.</td></tr></tbody></table><p>Do not open deprecated or unauthenticated endpoints such as the kubelet read-only port. Use the firewall guidance for the selected Kubernetes distribution and keep control-plane traffic private wherever possible.</p><h2 id="identity-and-sso" tabindex="-1">Identity and SSO <a class="header-anchor" href="#identity-and-sso" aria-label="Permalink to &quot;Identity and SSO&quot;">​</a></h2><p>Decide whether prokube will use local Keycloak users, an external corporate identity provider, or both. For corporate SSO, create an OIDC application with the organization&#39;s identity provider and connect it through Keycloak.</p><p>Before production rollout:</p><ul><li>configure external IdP integration if needed;</li><li>test login with a normal user and an administrator;</li><li>define default groups and workspace access process;</li><li>document break-glass administrator access;</li><li>define client-secret rotation ownership.</li></ul><p>See <a href="./identity_providers.html">Identity Providers</a> for external IdP guidance.</p><h2 id="registry-and-source-repositories" tabindex="-1">Registry and Source Repositories <a class="header-anchor" href="#registry-and-source-repositories" aria-label="Permalink to &quot;Registry and Source Repositories&quot;">​</a></h2><p>prokube workloads pull platform images, user images, pipeline component images, notebook images, and serving images. Users will often need to build and push their own images for custom notebooks, pipeline components, and model-serving containers.</p><p>Plan:</p><ul><li>which container registries are allowed;</li><li>where users can push custom images;</li><li>how global image pull secrets are managed;</li><li>how workspace-specific registry credentials are created;</li><li>which Git or GitOps repositories are authoritative for deployment configuration;</li><li>whether users can build and push images from Labs;</li><li>whether the source repository platform should support webhooks or CI integration for image builds.</li></ul><p>Common source platforms include GitHub, GitLab, Bitbucket, and self-hosted Git servers. The registry must be reachable from the cluster and should support the retention, vulnerability scanning, and access-control policy required by the organization.</p><p>See <a href="./operations_runbooks.html#workspace-defaults-and-image-pull-secrets">Workspace Defaults and Image Pull Secrets</a> and <a href="./../platform/kubernetes.html#registry-credentials">Registry Credentials</a>.</p><h2 id="storage-sizing" tabindex="-1">Storage Sizing <a class="header-anchor" href="#storage-sizing" aria-label="Permalink to &quot;Storage Sizing&quot;">​</a></h2><p>Object storage, notebook volumes, MLflow artifacts, pipeline artifacts, and model files can grow quickly. Size MinIO tenants, databases, and persistent-volume storage before onboarding users.</p><p>For production deployments, avoid accepting placeholder storage sizes from a demo installation. Define expected retention, dataset size, model size, pipeline concurrency, and backup requirements first.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./storage.html">Storage</a></li><li><a href="./backup_restore.html">Backup and Restore</a></li><li><a href="./identity_providers.html">Identity Providers</a></li><li><a href="./operations_runbooks.html">Operations Runbooks</a></li></ul>`,46)])])}const g=t(i,[["render",s]]);export{h as __pageData,g as default};
